104→                            .request_disable_account("nostr", &account_id, "relay pool shutdown")
105→                            .await;
106→                        break;
107→                    }
108→                    Ok(_) => {}
109→                    Err(e) => {
110→                        tracing::warn!(account_id, "notification channel error: {e}");
111→                    }
112→                }
113→            }
114→        }
115→    }
