 34→/// Configuration for a single Nostr account.
 35→#[derive(Clone, Serialize, Deserialize)]
 36→#[serde(default)]
 37→pub struct NostrAccountConfig {
 38→    /// Secret key in `nsec1...` (bech32) or 64-char hex format.
 39→    #[serde(serialize_with = "secret_serde::serialize_secret")]
 40→    pub secret_key: Secret<String>,
 41→
 42→    /// Relay WebSocket URLs (e.g. `wss://relay.damus.io`).
 43→    pub relays: Vec<String>,
 44→
 45→    /// DM access policy.
 46→    pub dm_policy: DmPolicy,
 47→
 48→    /// Public keys allowed to send DMs (npub1/hex).
 49→    pub allowed_pubkeys: Vec<String>,
 50→
 51→    /// Whether this account is enabled.
 52→    pub enabled: bool,
 53→
 54→    /// NIP-01 profile metadata to publish on connect.
 55→    #[serde(skip_serializing_if = "Option::is_none")]
 56→    pub profile: Option<NostrProfile>,
 57→
 58→    /// Default model ID for sessions created from this account.
 59→    #[serde(skip_serializing_if = "Option::is_none")]
 60→    pub model: Option<String>,
 61→
 62→    /// Provider name associated with the model.
 63→    #[serde(skip_serializing_if = "Option::is_none")]
 64→    pub model_provider: Option<String>,
 65→
 66→    /// Enable OTP self-approval for non-allowlisted DM users.
 67→    pub otp_self_approval: bool,
 68→
 69→    /// Cooldown in seconds after 3 failed OTP attempts.
 70→    pub otp_cooldown_secs: u64,
 71→}
 72→
 73→impl Default for NostrAccountConfig {
 74→    fn default() -> Self {
 75→        Self {
 76→            secret_key: Secret::new(String::new()),
 77→            relays: default_relays(),
 78→            dm_policy: DmPolicy::Allowlist,
 79→            allowed_pubkeys: Vec::new(),
 80→            enabled: true,
 81→            profile: None,
 82→            model: None,
 83→            model_provider: None,
 84→            otp_self_approval: true,
 85→            otp_cooldown_secs: 300,
 86→        }
 87→    }
 88→}
