268→#[async_trait]
269→impl ChannelStatus for TelegramPlugin {
270→    async fn probe(&self, account_id: &str) -> ChannelResult<ChannelHealthSnapshot> {
271→        // Return cached result if fresh enough.
272→        if let Ok(cache) = self.probe_cache.read()
273→            && let Some((snap, ts)) = cache.get(account_id)
274→            && ts.elapsed() < PROBE_CACHE_TTL
275→        {
276→            return Ok(snap.clone());
277→        }
278→
279→        let bot = {
280→            let accounts = self.accounts.read().unwrap_or_else(|e| e.into_inner());
281→            accounts.get(account_id).map(|s| s.bot.clone())
282→        };
283→
284→        let result = match bot {
285→            Some(bot) => match bot.get_me().await {
286→                Ok(me) => ChannelHealthSnapshot {
287→                    connected: true,
288→                    account_id: account_id.to_string(),
289→                    details: Some(format!(
290→                        "Bot: @{}",
291→                        me.username.as_deref().unwrap_or("unknown")
292→                    )),
293→                    extra: None,
294→                },
295→                Err(e) => ChannelHealthSnapshot {
296→                    connected: false,
297→                    account_id: account_id.to_string(),
298→                    details: Some(format!("API error: {e}")),
299→                    extra: None,
300→                },
301→            },
302→            None => ChannelHealthSnapshot {
303→                connected: false,
304→                account_id: account_id.to_string(),
305→                details: Some("account not started".into()),
306→                extra: None,
307→            },
308→        };
309→
310→        if let Ok(mut cache) = self.probe_cache.write() {
311→            cache.insert(account_id.to_string(), (result.clone(), Instant::now()));
312→        }
313→
314→        Ok(result)
315→    }
316→}
