123→    async fn start_account(
124→        &mut self,
125→        account_id: &str,
126→        config: serde_json::Value,
127→    ) -> ChannelResult<()> {
128→        let cfg: DiscordAccountConfig = serde_json::from_value(config)?;
129→        if cfg.token.expose_secret().is_empty() {
130→            return Err(ChannelError::invalid_input("Discord bot token is required"));
131→        }
132→
133→        info!(account_id, "starting discord account");
134→
135→        let cancel = tokio_util::sync::CancellationToken::new();
136→        let accounts_clone = Arc::clone(&self.accounts);
137→        let account_id_owned = account_id.to_string();
138→        let token = cfg.token.expose_secret().clone();
139→
140→        {
141→            let otp_cooldown = cfg.otp_cooldown_secs;
142→            let mut accounts = self.accounts.write().unwrap_or_else(|e| e.into_inner());
143→            accounts.insert(account_id.to_string(), AccountState {
144→                account_id: account_id.to_string(),
145→                config: cfg,
146→                message_log: self.message_log.clone(),
147→                event_sink: self.event_sink.clone(),
148→                cancel: cancel.clone(),
149→                bot_user_id: None,
150→                http: None,
151→                otp: std::sync::Mutex::new(OtpState::new(otp_cooldown)),
152→            });
153→        }
154→
155→        // Spawn the serenity client in a background task.
156→        let cancel_for_task = cancel.clone();
157→        tokio::spawn(async move {
158→            let handler = Handler::new(account_id_owned.clone(), Arc::clone(&accounts_clone));
159→
160→            let mut client = match serenity::Client::builder(&token, required_intents())
161→                .event_handler(handler)
162→                .await
163→            {
164→                Ok(c) => c,
165→                Err(e) => {
166→                    warn!(
167→                        account_id = %account_id_owned,
168→                        "failed to build Discord client: {e}"
169→                    );
170→                    return;
171→                },
172→            };
173→
174→            // Store the Http handle so outbound messages can use it.
175→            {
176→                let mut accounts = accounts_clone.write().unwrap_or_else(|e| e.into_inner());
177→                if let Some(state) = accounts.get_mut(&account_id_owned) {
178→                    state.http = Some(Arc::clone(&client.http));
179→                }
180→            }
181→
182→            tokio::select! {
183→                result = client.start() => {
184→                    if let Err(e) = result {
185→                        warn!(
186→                            account_id = %account_id_owned,
187→                            "Discord client stopped with error: {e}"
188→                        );
189→                    }
190→                }
191→                () = cancel_for_task.cancelled() => {
192→                    info!(account_id = %account_id_owned, "Discord client shutting down");
193→                    client.shard_manager.shutdown_all().await;
194→                }
195→            }
196→        });
197→
198→        Ok(())
199→    }
200→
201→    async fn stop_account(&mut self, account_id: &str) -> ChannelResult<()> {
202→        let cancel = {
203→            let mut accounts = self.accounts.write().unwrap_or_else(|e| e.into_inner());
204→            accounts.remove(account_id).map(|s| s.cancel)
205→        };
206→        if let Some(cancel) = cancel {
207→            cancel.cancel();
208→        } else {
209→            warn!(account_id, "Discord account not found");
210→        }
211→        Ok(())
212→    }
