279→impl ChannelStatus for DiscordPlugin {
280→    async fn probe(&self, account_id: &str) -> ChannelResult<ChannelHealthSnapshot> {
281→        let accounts = self.accounts.read().unwrap_or_else(|e| e.into_inner());
282→        if let Some(state) = accounts.get(account_id) {
283→            let connected = state.bot_user_id.is_some();
284→            let details = if connected {
285→                "gateway connected".to_string()
286→            } else {
287→                "connecting to Discord gateway...".to_string()
288→            };
289→            Ok(ChannelHealthSnapshot {
290→                connected,
291→                account_id: state.account_id.clone(),
292→                details: Some(details),
293→                extra: None,
294→            })
295→        } else {
296→            Ok(ChannelHealthSnapshot {
