115→impl ChannelPlugin for SlackPlugin {
116→    fn id(&self) -> &str {
117→        "slack"
118→    }
119→
120→    fn name(&self) -> &str {
121→        "Slack"
122→    }
123→
124→    async fn start_account(
125→        &mut self,
126→        account_id: &str,
127→        config: serde_json::Value,
128→    ) -> ChannelResult<()> {
129→        let cfg: SlackAccountConfig = serde_json::from_value(config)?;
130→        if cfg.bot_token.expose_secret().is_empty() {
131→            return Err(ChannelError::invalid_input("Slack bot_token is required"));
132→        }
133→
134→        match cfg.connection_mode {
135→            crate::config::ConnectionMode::SocketMode => {
136→                if cfg.app_token.expose_secret().is_empty() {
137→                    return Err(ChannelError::invalid_input(
138→                        "Slack app_token is required for Socket Mode",
139→                    ));
140→                }
141→                info!(account_id, "starting slack account (socket mode)");
142→                crate::socket::start_socket_mode(
143→                    account_id,
144→                    cfg,
145→                    Arc::clone(&self.accounts),
146→                    self.message_log.clone(),
147→                    self.event_sink.clone(),
148→                )
149→                .await
150→            },
151→            crate::config::ConnectionMode::EventsApi => {
152→                if cfg
153→                    .signing_secret
154→                    .as_ref()
155→                    .is_none_or(|s| s.expose_secret().is_empty())
156→                {
157→                    return Err(ChannelError::invalid_input(
158→                        "Slack signing_secret is required for Events API mode",
159→                    ));
160→                }
161→                info!(account_id, "starting slack account (events api)");
162→                crate::webhook::register_events_api_account(
163→                    account_id,
164→                    cfg,
165→                    Arc::clone(&self.accounts),
166→                    self.message_log.clone(),
167→                    self.event_sink.clone(),
168→                )
169→                .await
170→            },
171→        }
172→    }
173→
174→    async fn stop_account(&mut self, account_id: &str) -> ChannelResult<()> {
175→        let cancel = {
176→            let mut accounts = self.accounts.write().unwrap_or_else(|e| e.into_inner());
177→            accounts.remove(account_id).map(|s| s.cancel)
178→        };
179→        if let Some(cancel) = cancel {
180→            cancel.cancel();
181→            info!(account_id, "stopped slack account");
182→        } else {
183→            warn!(account_id, "slack account not found");
184→        }
185→        Ok(())
186→    }
187→
188→    fn outbound(&self) -> Option<&dyn ChannelOutbound> {
189→        Some(&self.outbound)
190→    }
191→
192→    fn status(&self) -> Option<&dyn ChannelStatus> {
193→        Some(self)
194→    }
195→
196→    fn has_account(&self, account_id: &str) -> bool {
197→        let accounts = self.accounts.read().unwrap_or_else(|e| e.into_inner());
198→        accounts.contains_key(account_id)
199→    }
200→
201→    fn account_ids(&self) -> Vec<String> {
202→        let accounts = self.accounts.read().unwrap_or_else(|e| e.into_inner());
203→        accounts.keys().cloned().collect()
204→    }
205→
206→    fn account_config(&self, account_id: &str) -> Option<Box<dyn ChannelConfigView>> {
207→        let accounts = self.accounts.read().unwrap_or_else(|e| e.into_inner());
208→        accounts
209→            .get(account_id)
210→            .map(|s| Box::new(s.config.clone()) as Box<dyn ChannelConfigView>)
211→    }
212→
213→    fn account_config_json(&self, account_id: &str) -> Option<serde_json::Value> {
214→        let accounts = self.accounts.read().unwrap_or_else(|e| e.into_inner());
215→        accounts
216→            .get(account_id)
217→            .and_then(|s| serde_json::to_value(crate::config::RedactedConfig(&s.config)).ok())
218→    }
219→
220→    fn update_account_config(
221→        &self,
222→        account_id: &str,
223→        config: serde_json::Value,
224→    ) -> ChannelResult<()> {
225→        let parsed: SlackAccountConfig = serde_json::from_value(config)?;
226→        let mut accounts = self.accounts.write().unwrap_or_else(|e| e.into_inner());
227→        if let Some(state) = accounts.get_mut(account_id) {
228→            state.config = parsed;
229→            Ok(())
230→        } else {
231→            Err(ChannelError::unknown_account(account_id))
232→        }
233→    }
234→
235→    fn shared_outbound(&self) -> Arc<dyn ChannelOutbound> {
236→        Arc::new(SlackOutbound {
237→            accounts: Arc::clone(&self.accounts),
238→        })
239→    }
240→
241→    fn shared_stream_outbound(&self) -> Arc<dyn ChannelStreamOutbound> {
242→        Arc::new(SlackOutbound {
243→            accounts: Arc::clone(&self.accounts),
244→        })
245→    }
246→
247→    fn thread_context(&self) -> Option<&dyn ChannelThreadContext> {
248→        Some(&self.outbound)
249→    }
