143→#[async_trait]
144→impl ChannelPlugin for WhatsAppPlugin {
145→    fn id(&self) -> &str {
146→        "whatsapp"
147→    }
148→
149→    fn name(&self) -> &str {
150→        "WhatsApp"
151→    }
152→
153→    async fn start_account(
154→        &mut self,
155→        account_id: &str,
156→        config: serde_json::Value,
157→    ) -> ChannelResult<()> {
158→        // If the account is already running (e.g. started from stored channels
159→        // on boot), skip re-starting to avoid sled lock conflicts.
160→        if self.has_account(account_id) {
161→            info!(
162→                account_id,
163→                "WhatsApp account already running, skipping start"
164→            );
165→            return Ok(());
166→        }
167→
168→        let wa_config: WhatsAppAccountConfig = serde_json::from_value(config)?;
169→
170→        info!(account_id, "starting WhatsApp account");
171→
172→        connection::start_connection(
173→            account_id.to_string(),
174→            wa_config,
175→            Arc::clone(&self.accounts),
176→            self.data_dir.clone(),
177→            self.message_log.clone(),
178→            self.event_sink.clone(),
179→        )
180→        .await
181→        .map_err(|e| moltis_channels::Error::unavailable(format!("whatsapp start: {e}")))?;
182→
183→        Ok(())
184→    }
185→
186→    async fn stop_account(&mut self, account_id: &str) -> ChannelResult<()> {
187→        let stop_ctx = {
188→            let accounts = self.accounts.read().unwrap_or_else(|e| e.into_inner());
189→            accounts
190→                .get(account_id)
191→                .map(|s| (s.cancel.clone(), Arc::clone(&s.shutdown)))
192→        };
193→
194→        if let Some((cancel, shutdown)) = stop_ctx {
195→            info!(account_id, "stopping WhatsApp account");
196→            cancel.cancel();
197→
198→            if !shutdown.is_done()
199→                && timeout(Duration::from_secs(10), shutdown.wait())
200→                    .await
201→                    .is_err()
202→            {
203→                warn!(account_id, "timeout waiting for WhatsApp account shutdown");
204→            }
205→
206→            let mut accounts = self.accounts.write().unwrap_or_else(|e| e.into_inner());
207→            accounts.remove(account_id);
208→        } else {
209→            warn!(account_id, "WhatsApp account not found");
210→        }
211→
212→        Ok(())
213→    }
