 15→/// Maximum number of sent message IDs to track for self-chat loop detection.
 16→const SENT_IDS_CAPACITY: usize = 256;
 17→
 18→/// Invisible Unicode watermark appended to every bot-sent message.
 19→///
 20→/// A sequence of ZWJ (U+200D) and ZWNJ (U+200C) characters that is:
 21→/// - Invisible to the user
 22→/// - Preserved by WhatsApp (both are required for emoji/script rendering)
 23→/// - Linguistically meaningless as an alternating pattern
 24→///
 25→/// Used as a secondary self-chat loop detection alongside message-ID tracking.
 26→pub(crate) const BOT_WATERMARK: &str = "\u{200D}\u{200C}\u{200D}\u{200C}";
 27→
 28→/// Shared account state map.
 29→pub type AccountStateMap = Arc<RwLock<HashMap<String, AccountState>>>;
 30→
 31→/// Synchronization primitive for graceful bot shutdown.
 32→pub struct ShutdownState {
 33→    done: AtomicBool,
 34→    notify: Notify,
 35→}
 36→
 37→impl Default for ShutdownState {
 38→    fn default() -> Self {
 39→        Self::new()
 40→    }
 41→}
 42→
 43→impl ShutdownState {
 44→    pub fn new() -> Self {
 45→        Self {
 46→            done: AtomicBool::new(false),
 47→            notify: Notify::new(),
 48→        }
 49→    }
 50→
 51→    pub fn is_done(&self) -> bool {
 52→        self.done.load(Ordering::Acquire)
 53→    }
 54→
 55→    pub fn mark_done(&self) {
 56→        self.done.store(true, Ordering::Release);
 57→        self.notify.notify_waiters();
 58→    }
 59→
 60→    pub async fn wait(&self) {
 61→        loop {
 62→            let notified = self.notify.notified();
 63→            if self.is_done() {
 64→                return;
 65→            }
 66→            notified.await;
 67→        }
 68→    }
 69→}
