 71→/// Per-account runtime state.
 72→pub struct AccountState {
 73→    pub client: Arc<Client>,
 74→    pub account_id: String,
 75→    pub config: WhatsAppAccountConfig,
 76→    pub cancel: CancellationToken,
 77→    pub shutdown: Arc<ShutdownState>,
 78→    pub message_log: Option<Arc<dyn MessageLog>>,
 79→    pub event_sink: Option<Arc<dyn ChannelEventSink>>,
 80→    /// Latest QR code data for the pairing flow (updated every ~20s).
 81→    pub latest_qr: RwLock<Option<String>>,
 82→    /// Whether the client is currently connected.
 83→    pub connected: AtomicBool,
 84→    /// In-memory OTP challenges for self-approval (std::sync::Mutex because
 85→    /// all OTP operations are synchronous HashMap lookups, never held across
 86→    /// `.await` points).
 87→    pub otp: Mutex<OtpState>,
 88→    /// Recently sent message IDs, used to distinguish bot echoes from user
 89→    /// messages in self-chat. When the bot sends a message, the ID is recorded
 90→    /// here. Incoming `is_from_me` messages whose ID matches are bot echoes
 91→    /// and get skipped; non-matching ones are genuine user messages from
 92→    /// another device (phone, WhatsApp Web) and get processed.
 93→    pub(crate) recent_sent_ids: Mutex<VecDeque<String>>,
 94→}
