 96→impl AccountState {
 97→    /// Record a message ID that was sent by the bot, for self-chat loop detection.
 98→    pub fn record_sent_id(&self, id: &str) {
 99→        let mut ids = self
100→            .recent_sent_ids
101→            .lock()
102→            .unwrap_or_else(|e| e.into_inner());
103→        if ids.len() >= SENT_IDS_CAPACITY {
104→            ids.pop_front();
105→        }
106→        ids.push_back(id.to_string());
107→    }
108→
109→    /// Check if a message ID was recently sent by the bot.
110→    pub fn was_sent_by_us(&self, id: &str) -> bool {
111→        let ids = self
112→            .recent_sent_ids
113→            .lock()
114→            .unwrap_or_else(|e| e.into_inner());
115→        ids.iter().any(|sent_id| sent_id == id)
116→    }
117→
118→    /// Send a WhatsApp message and record its ID for self-chat loop detection.
119→    /// Appends an invisible watermark to text messages for secondary loop detection.
120→    pub async fn send_message(
121→        &self,
122→        to: wacore_binary::jid::Jid,
123→        mut msg: waproto::whatsapp::Message,
124→    ) -> crate::Result<()> {
125→        watermark_message(&mut msg);
126→        let msg_id =
127→            self.client
128→                .send_message(to, msg)
129→                .await
130→                .map_err(|e| crate::Error::Whatsapp {
131→                    message: e.to_string(),
132→                })?;
133→        self.record_sent_id(&msg_id);
134→        Ok(())
135→    }
136→}
