                    extra: Some(serde_json::json!({
                        "pubkey": npub,
                        "connected_relays": connected_count,
                        "total_relays": total,
                    })),
                })
            },
            None => Ok(ChannelHealthSnapshot {
                connected: false,
                account_id: account_id.to_string(),
                details: Some("account not found".to_string()),
                extra: None,
            }),
        }
    }
